import { useMemo, useState } from "react";
import jsPDF from "jspdf";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);

    const [resumeFile, setResumeFile] = useState(null);
    const [jdFile, setJdFile] = useState(null);

    const [resumeMsg, setResumeMsg] = useState("");
    const [jdMsg, setJdMsg] = useState("");

    const [loading, setLoading] = useState(false);
    const [darkMode, setDarkMode] = useState(false);

    const theme = useMemo(() => {
        return darkMode
            ? { bg: "#0f172a", card: "#111827", text: "#f9fafb" }
            : { bg: "#f8fafc", card: "#ffffff", text: "#111827" };
    }, [darkMode]);

    /* ---------------- UPLOAD RESUME ---------------- */
    const uploadResume = async () => {
        if (!resumeFile) {
            setResumeMsg("❌ Please select a resume PDF");
            return;
        }

        const formData = new FormData();
        formData.append("resume", resumeFile);

        setLoading(true);
        setResumeMsg("");

        const res = await fetch("http://localhost:5000/upload", {
            method: "POST",
            body: formData
        });

        const data = await res.json();

        setLoading(false);

        if (!data.extractedText) {
            setResumeMsg(data.message); // ❌ wrong file handled here
            return;
        }

        setResumeText(data.extractedText);
        setResumeMsg(data.message);
    };

    /* ---------------- UPLOAD JD ---------------- */
    const uploadJD = async () => {
        if (!jdFile) {
            setJdMsg("❌ Please select a JD PDF");
            return;
        }

        const formData = new FormData();
        formData.append("jdFile", jdFile);

        setLoading(true);
        setJdMsg("");

        const res = await fetch("http://localhost:5000/upload-jd", {
            method: "POST",
            body: formData
        });

        const data = await res.json();

        setLoading(false);

        if (!data.extractedText) {
            setJdMsg(data.message); // ❌ wrong file handled here
            return;
        }

        setJobDescription(data.extractedText);
        setJdMsg(data.message);
    };

    /* ---------------- ANALYZE ---------------- */
    const analyze = async () => {
        if (!resumeText || !jobDescription) {
            alert("Upload Resume + JD first");
            return;
        }

        setLoading(true);

        const res = await fetch("http://localhost:5000/analyze", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({ resumeText, jobDescription })
        });

        const data = await res.json();

        setAnalysis(data);
        setLoading(false);
    };

    /* ---------------- PDF DOWNLOAD ---------------- */
    const downloadReport = () => {
        if (!analysis) return;

        const doc = new jsPDF();
        doc.text("AI Resume Analyzer Report", 10, 10);
        doc.text(`Score: ${analysis.score}`, 10, 20);

        doc.text("Matched Skills:", 10, 30);
        analysis.matchedSkills.forEach((s, i) => {
            doc.text("- " + s, 10, 40 + i * 6);
        });

        doc.save("report.pdf");
    };

    return (
        <div style={{ background: theme.bg, minHeight: "100vh", padding: 20 }}>
            <div style={{ maxWidth: 900, margin: "auto", background: theme.card, padding: 20, color: theme.text }}>

                <h1>AI Resume Analyzer 🚀</h1>

                <button onClick={() => setDarkMode(!darkMode)}>
                    Toggle Mode
                </button>

                {/* RESUME */}
                <h3>Upload Resume</h3>
                <input type="file" onChange={(e) => setResumeFile(e.target.files[0])} />
                <button onClick={uploadResume}>
                    {loading ? "Uploading..." : "Upload Resume"}
                </button>
                <p>{resumeMsg}</p>

                {/* JD */}
                <h3>Upload Job Description</h3>
                <input type="file" onChange={(e) => setJdFile(e.target.files[0])} />
                <button onClick={uploadJD}>
                    {loading ? "Uploading..." : "Upload JD"}
                </button>
                <p>{jdMsg}</p>

                {/* ANALYZE */}
                <button onClick={analyze}>
                    Analyze Match
                </button>

                {/* RESULT */}
                {analysis && (
                    <div>
                        <h2>Score: {analysis.score}</h2>

                        <h3>Matched Skills</h3>
                        {analysis.matchedSkills.map((s, i) => (
                            <span key={i}> {s} </span>
                        ))}

                        <h3>Missing Skills</h3>
                        {analysis.missingSkills.map((s, i) => (
                            <span key={i}> {s} </span>
                        ))}

                        <button onClick={downloadReport}>
                            Download PDF
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
}

export default App;
